mapper.sql:
SELECT X.USER_ID , X.STDNT_NO , X.SBJCT_ID , X.SCR_CNVS_STSCD , X.SCR_MRK_GRDCD , X.DEPTNM , X.USERNM , X.TOT_SCR , X.LST_SCR , X.ADTN_SCR , X.ETC_SCR , X.ATNDC_SCORE , X.ATNDC_SCORE_RATIO , ROUND((CAST(CASE WHEN X.ATNDC_SCORE < 0 THEN 0 ELSE X.ATNDC_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.ATNDC_SCORE_RATIO AS NUMBER(5, 2)), 2) AS ATNDC_SCORE_AVG , X.ATNDC_ITEM_ID , X.MIDEXAM_SCORE , X.MIDEXAM_SCORE_RATIO , ROUND((CAST(CASE WHEN X.MIDEXAM_SCORE < 0 THEN 0 ELSE X.MIDEXAM_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.MIDEXAM_SCORE_RATIO AS NUMBER(5, 2)), 2) AS MIDEXAM_SCORE_AVG , X.MIDEXAM_ITEM_ID , X.LSTEXAM_SCORE , X.LSTEXAM_SCORE_RATIO , ROUND((CAST(CASE WHEN X.LSTEXAM_SCORE < 0 THEN 0 ELSE X.LSTEXAM_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.LSTEXAM_SCORE_RATIO AS NUMBER(5, 2)), 2) AS LSTEXAM_SCORE_AVG , X.LSTEXAM_ITEM_ID , X.ASMT_SCORE , X.ASMT_SCORE_RATIO , ROUND((CAST(CASE WHEN X.ASMT_SCORE < 0 THEN 0 ELSE X.ASMT_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.ASMT_SCORE_RATIO AS NUMBER(5, 2)), 2) AS ASMT_SCORE_AVG , X.ASMT_ITEM_ID , X.DSCS_SCORE , X.DSCS_SCORE_RATIO , ROUND((CAST(CASE WHEN X.DSCS_SCORE < 0 THEN 0 ELSE X.DSCS_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.DSCS_SCORE_RATIO AS NUMBER(5, 2)), 2) AS DSCS_SCORE_AVG , X.DSCS_ITEM_ID , X.QUIZ_SCORE , X.QUIZ_SCORE_RATIO , ROUND((CAST(CASE WHEN X.QUIZ_SCORE < 0 THEN 0 ELSE X.QUIZ_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.QUIZ_SCORE_RATIO AS NUMBER(5, 2)), 2) AS QUIZ_SCORE_AVG , X.QUIZ_ITEM_ID , X.SRVY_SCORE , X.SRVY_SCORE_RATIO , ROUND((CAST(CASE WHEN X.SRVY_SCORE < 0 THEN 0 ELSE X.SRVY_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.SRVY_SCORE_RATIO AS NUMBER(5, 2)), 2) AS SRVY_SCORE_AVG , X.SRVY_ITEM_ID , X.SMNR_SCORE , X.SMNR_SCORE_RATIO , ROUND((CAST(CASE WHEN X.SMNR_SCORE < 0 THEN 0 ELSE X.SMNR_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.SMNR_SCORE_RATIO AS NUMBER(5, 2)), 2) AS SMNR_SCORE_AVG , X.SMNR_ITEM_ID , X.PROF_MEMO , ROUND( ROUND((CAST(CASE WHEN X.ATNDC_SCORE < 0 THEN 0 ELSE X.ATNDC_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.ATNDC_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.MIDEXAM_SCORE < 0 THEN 0 ELSE X.MIDEXAM_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.MIDEXAM_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.LSTEXAM_SCORE < 0 THEN 0 ELSE X.LSTEXAM_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.LSTEXAM_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.ASMT_SCORE < 0 THEN 0 ELSE X.ASMT_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.ASMT_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.DSCS_SCORE < 0 THEN 0 ELSE X.DSCS_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.DSCS_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.QUIZ_SCORE < 0 THEN 0 ELSE X.QUIZ_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.QUIZ_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.SRVY_SCORE < 0 THEN 0 ELSE X.SRVY_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.SRVY_SCORE_RATIO AS NUMBER(5, 2)), 2) + ROUND((CAST(CASE WHEN X.SMNR_SCORE < 0 THEN 0 ELSE X.SMNR_SCORE END AS NUMBER(5, 2)) / 100) * CAST(X.SMNR_SCORE_RATIO AS NUMBER(5, 2)), 2) , 2) AS CAL_TOT_SCR , X.MIDDLE_TEST_USE_YN , X.LAST_TEST_USE_YN , X.MIDDLE_TEST_NO_YN_2 , X.LAST_TEST_NO_YN_2 FROM ( SELECT A.USER_ID , USR.STDNT_NO , D.SBJCT_ID , MAX(A.SCR_CNVS_STSCD) AS SCR_CNVS_STSCD , MAX(A.SCR_MRK_GRDCD) AS SCR_MRK_GRDCD , MAX(DEPT.DEPTNM) AS DEPTNM -- , MAX(NVL(SCYR, '-')) AS SCYR , MAX(USR.USERNM) AS USERNM -- , MAX(USR.MOBILE_NO) AS MOBILE_NO -- , MAX(USR.EMAIL) AS EMAIL , MAX(A.ADTN_SCR) AS ADTN_SCR , MAX(A.TOT_SCR) AS TOT_SCR , MAX(A.LST_SCR) AS LST_SCR , MAX(A.ETC_SCR) AS ETC_SCR , MAX(A.PROF_MEMO) AS PROF_MEMO -- , MAX(CASE WHEN C.MRK_ITM_TYCD = 'MIDEXAM' THEN B.SCR ELSE 0 END) AS MIDEXAM_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'LSTEXAM' THEN B.SCR ELSE 0 END) AS LSTEXAM_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'ATNDC' THEN B.SCR ELSE 0 END) AS ATNDC_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'ASMT' THEN B.SCR ELSE 0 END) AS ASMT_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'DSCS' THEN B.SCR ELSE 0 END) AS DSCS_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'QUIZ' THEN B.SCR ELSE 0 END) AS QUIZ_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'SRVY' THEN B.SCR ELSE 0 END) AS SRVY_SCORE , MAX(CASE WHEN C.MRK_ITM_TYCD = 'SMNR' THEN B.SCR ELSE 0 END) AS SMNR_SCORE -- , MAX(CASE WHEN C.MRK_ITM_TYCD = 'MIDEXAM' THEN C.MRK_RFLTRT ELSE 0 END) AS MIDEXAM_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'MIDEXAM' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS MIDEXAM_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'LSTEXAM' THEN C.MRK_RFLTRT ELSE 0 END) AS LSTEXAM_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'LSTEXAM' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS LSTEXAM_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'ATNDC' THEN C.MRK_RFLTRT ELSE 0 END) AS ATNDC_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'ATNDC' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS ATNDC_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'ASMT' THEN C.MRK_RFLTRT ELSE 0 END) AS ASMT_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'ASMT' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS ASMT_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'DSCS' THEN C.MRK_RFLTRT ELSE 0 END) AS DSCS_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'DSCS' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS DSCS_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'QUIZ' THEN C.MRK_RFLTRT ELSE 0 END) AS QUIZ_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'QUIZ' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS QUIZ_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'SRVY' THEN C.MRK_RFLTRT ELSE 0 END) AS SRVY_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'SRVY' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS SRVY_ITEM_ID , MAX(CASE WHEN C.MRK_ITM_TYCD = 'SMNR' THEN C.MRK_RFLTRT ELSE 0 END) AS SMNR_SCORE_RATIO , MAX(CASE WHEN C.MRK_ITM_TYCD = 'SMNR' THEN B.MRK_SBJCT_DTL_ID ELSE '-' END) AS SMNR_ITEM_ID -- , MAX(CASE WHEN C.MRK_ITM_TYCD = 'MIDEXAM' AND NVL(C.MRK_RFLTRT, 0) > 0 THEN 'Y' ELSE 'N'END) AS MIDDLE_TEST_USE_YN , MAX(CASE WHEN C.MRK_ITM_TYCD = 'LSTEXAM' AND NVL(C.MRK_RFLTRT, 0) > 0 THEN 'Y' ELSE 'N'END) AS LAST_TEST_USE_YN , MAX(CASE WHEN C.MRK_ITM_TYCD = 'MIDEXAM' AND NVL(C.MRK_RFLTRT, 0) > 0 AND B.SCR = -1 THEN 'Y' ELSE 'N' END) AS MIDDLE_TEST_NO_YN_2 , MAX(CASE WHEN C.MRK_ITM_TYCD = 'LSTEXAM' AND NVL(C.MRK_RFLTRT, 0) > 0 AND B.SCR = -1 THEN 'Y' ELSE 'N' END) AS LAST_TEST_NO_YN_2 FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_MRK_SBJCT_DTL B ON (A.MRK_SBJCT_ID = B.MRK_SBJCT_ID) JOIN TB_LMS_MRK_ITM_STNG C ON (A.SBJCT_ID = C.SBJCT_ID AND B.MRK_ITM_TYCD = C.MRK_ITM_TYCD) JOIN TB_LMS_ATNDLC D ON (D.USER_ID = A.USER_ID AND D.ATNDLC_STSCD = 'ATNDLC' AND D.AUDITYN = 'N' AND D.SBJCT_ID = #{sbjctId}) JOIN TB_LMS_USER USR ON (D.USER_ID = USR.USER_ID) JOIN TB_LMS_DEPT DEPT ON (USR.DEPT_ID = DEPT.DEPT_ID) GROUP BY A.USER_ID, USR.STDNT_NO, D.SBJCT_ID ) X WHERE 1=1
AND ( X.DEPTNM LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR X.USER_ID LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR X.USERNM LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND X.USER_ID IN (
#{stdNos}
)

mapper.select:
/* SQL ID : MarkSubjectDAO.stdMrkList 설 명 : */ WITH EXAM_ABSNCE_T AS ( /*결시 신청*/ SELECT * FROM ( SELECT ROW_NUMBER()OVER(PARTITION BY A.EXAM_BSC_ID, A.USER_ID ORDER BY A.REG_DTTM DESC ) AS RN , A.USER_ID , A.APLY_STSCD , B.EXAM_GBNCD , B.TKEXAM_MTHD_CD FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_EXAM_BSC B ON A.EXAM_BSC_ID = B.EXAM_BSC_ID AND B.SBJCT_ID = #{sbjctId} AND B.EXAM_GBNCD IN ('EXAM_MID', 'EXAM_MID_TEAM','EXAM_LST', 'EXAM_LST_TEAM') AND B.TKEXAM_MTHD_CD = 'RLTM' WHERE 1=1 AND A.APLY_STSCD IN ('APLY', 'RE_APLY', 'APRV') )A WHERE A.RN = 1 ), NO_EVL_T AS (
) SELECT ROW_NUMBER() OVER(ORDER BY XXX.USERNM ASC) AS LINE_NO , XXX.* FROM ( SELECT XX.* , (SELECT APLY_STSCD FROM EXAM_ABSNCE_T WHERE USER_ID = XX.USER_ID AND TKEXAM_MTHD_CD = 'M') AS APPR_STAT_M , (SELECT APLY_STSCD FROM EXAM_ABSNCE_T WHERE USER_ID = XX.USER_ID AND TKEXAM_MTHD_CD = 'L') AS APPR_STAT_L , (SELECT MID_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS MID_NO_EVL_CNT , (SELECT LAST_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS LAST_NO_EVL_CNT , (SELECT ASMT_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS ASMT_NO_EVL_CNT , (SELECT DSCS_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS DSCS_NO_EVL_CNT , (SELECT QUIZ_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS QUIZ_NO_EVL_CNT , (SELECT SRVY_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS SRVY_NO_EVL_CNT , (SELECT SMNR_NO_EVL_CNT FROM NO_EVL_T WHERE USER_ID = XX.USER_ID) AS SMNR_NO_EVL_CNT FROM (
) XX ) XXX WHERE 1=1
AND (MID_NO_EVAL_CNT + LAST_NO_EVAL_CNT + ASMNT_NO_EVAL_CNT + FORUM_NO_EVAL_CNT + QUIZ_NO_EVAL_CNT + TEST_NO_EVAL_CNT + RESCH_NO_EVAL_CNT) > 0

mapper.delete:
/*
    SQL ID: markSubjectDAO.allStdMrkSbjctDelete
    설  명 : 해당 과목의 모든 학생 성적 데이터를 삭제한다.
*/
DELETE FROM TB_LMS_MRK_SBJCT SBJ
WHERE SBJ.USER_ID IN (
    SELECT USER_ID
    FROM TB_LMS_ATNDLC STD
    WHERE STD.SBJCT_ID = #{sbjctId}
)

/*
    SQL ID: markSubjectDAO.allStdMrkSbjctDtlDelete
    설  명 : 해당 과목의 모든 학생 성적 상세 데이터를 삭제한다.
*/
DELETE FROM TB_LMS_MRK_SBJCT_DTL DTL
WHERE DTL.MRK_ITM_TYCD IN (
    SELECT X.MRK_ITM_TYCD
    FROM TB_LMS_MRK_ITM_STNG X
    WHERE X.SBJCT_ID = #{sbjctId}
)

mapper.insert:
/*
    SQL ID : markSubjectDAO.mrkSbjctBatchInsert
    설  명 : 학생들의 성적과목 데이터를 등록한다.
*/

    INSERT INTO TB_LMS_MRK_SBJCT (
          MRK_SBJCT_ID
        , USER_ID
        , SBJCT_ID
        , SCR_CNVS_STSCD
        , RGTR_ID
        , REG_DTTM
        , TOT_SCR
        , LST_SCR
        , ADTN_SCR
    )VALUES (
          #{item.mrkSbjctId}
        , #{item.userId}
        , #{item.sbjctId}
        , #{item.scrCnvsStscd}
        , #{item.rgtrId}
        , FN_DTTM()
        , #{item.totScr}
        , #{item.lstScr}
        , #{item.adtnScr}
    )

/*
    SQL ID : markSubjectDAO.mrkSbjctDtlBatchInsert
    설  명 : 학생들의 성적과목 상세 데이터를 등록한다.
*/

    INSERT INTO TB_LMS_MRK_SBJCT_DTL (
          MRK_SBJCT_DTL_ID
        , MRK_SBJCT_ID
        , MRK_ITM_TYCD
        , SCR
        , RGTR_ID
        , REG_DTTM
    )VALUES (
          #{item.mrkSbjctDtlId}
        , #{item.mrkSbjctId}
        , #{item.mrkItmTycd}
        , #{item.scr}
        , #{item.rgtrId}
        , FN_DTTM()
    )
